head.script:
	scwin.initData = {
		"chart" : {
			"prdctnUnit" : 10,
			"prdctnIntervalCount" : 3,
			"cnstnUnit" : 10,
			"cnstnIntervalCount" : 3,
			"sliderIntervalTime" : 5000,
			"displayData" : {
				"PC" : {"전력 생산량 / 전력 소비량 및 정산금액" : ["건수", "용량", "금액"]},
				"Plan" : {"계획" : ["건수", "용량", "금액"]},
				"Cnstrc" : {"건설" : ["건수", "용량", "금액"]},
				"Prdctn" : {"생산" : ["연 생산량(GWh)", "월 생산량(GWh)"]},
				"Cnstn" : {"소비" : ["연 소비량(GWh)", "월 소비량(GWh)"]},
				"MngReprMntnc" : {"관리" : ["수선유지", "개대체", "점검정비"]},
				"ElyrsErn" : {"정산" : ["발전 수익", "기타 수익", "소비 정산"]},
				"Dsuse" : {"폐기" : ["건수", "용량", "금액"]}
			}
		},
		"basinDisplayData" : [
			{"order" : "0", "name" : "탄소중립율", "value" : "cbnNtrlt", "tooltip" : "탄소 감축량 / 탄소 배출량 × 100"},
			{"order" : "1", "name" : "전력생산량", "value" : "pn", "tooltip" : "K-water 전체 생산전력량"},
			{"order" : "2", "name" : "전력소비량", "value" : "cn", "tooltip" : "K-water 전체 소비전력량"},
			{"order" : "3", "name" : "에너지정산", "value" : "cl", "tooltip" : "수익정산 - 소비정산"}
		],
		"prdctnDisplayData" : {
			"Lgwtpw" : "대수력",
			"Smlhp" : "소수력",
			"Tdpw" : "조력",
			"Snpw" : "태양광",
			"Wdpw" : "풍력",
			"Wtht" : "수열"
		},
		"setcscDivCd" : {
			"대수력" : 10,
			"소수력" : 21,
			"보소수력" : 22,
			"조력" : 30,
			"태양광" : 40,
			"풍력" : 50,
			"수열" : 60,
		},
		"cnstnDisplayData" : {
			"Itkpl" : "취수시설",
			"Prnplc" : "가압시설",
			"Fltplt" : "정수시설",
			"Etc" : "그외"
		},
		"titleClickEvent" : {
			"plan" : "ECSEC100000",
			"cnstrc" : "ECSEC100000",
			"mng" : "ECSEC100000",
			"excclc" : "ECSEC300000",
			"prdctn" : "ECSEC200000",
			"cnstn" : "ECSEC200000",
			"dsuse" : "ECSEC100000",
			"ntrlt" : "ECSEC410000"
		},
		"observeEvent" : false,
	};

	/**
	 * 화면 초기화에 필요한 로직을 수행한다.
	 */
	scwin.initScreen = function() {
		if (typeof utilLib.changeSkin != "undefined") {
			utilLib.changeSkin(window);
		}

		// 초기정보 set
		scwin.initInfo();

		// 데이터 조회
		scwin.searchDatas();

		// 슬라이드 차트 생성
		scwin.chartSlide(grpMainChartList, scwin.initData.chart.displayData);
		// 전주기 현황 타이틀 클릭 이벤트
		scwin.setCycleLabelClickEvent();
		// 탄소중립 현황 타이틀 클릭시 이동 이벤트 등록
		scwin.setGrpMainChartCbnNtrltClickEvent();
		// 유역현황도 체크박스 데이터 및 마우스 오버 이벤트
		scwin.setBasinDisplayData();
		ecsLib.setChartResizeObserver(this);
	};

	/**
	 * 초기정보 set
	 */
	scwin.initInfo = function() {
		// 사용자정보
		tbxMemInfo.setValue(comLib.getUsrNm() + "(" + comLib.getUsrEmpno()
			+ ") 님 환영합니다. [" + comLib.getUsrDeptNm() + "]");
		// 메세지 삭제
		$(".profile_info>div:last-child").css({
			"background" : 'url("")'
		});
		// 접속시간
		// WebSquare.util.setInterval(scwin.setCurtTime, {delay : 1000});
		scwin.setCurtTime();
		// 접속아이피
		spnUsrIp.setValue(comLib.getConectIp());
		// rMateMapChart 생성
		$(".wrap_ecs_menu ul li:nth-child(1) .w2anchor2").trigger("click");
		// $(".wrap_ecs_main > div").hide();
		// $(".wrap_ecs_main .main_01").show();
		// dmaSearchParam.set("nttClsCd", "");

		// 공지사항 이동
		$("a[id$=NttMove]").click(function() {
			top.comLib.initBoard($p, "ntt, 01, ECS0000000001");
		});
	};

	/**
	 * 현재시간 세팅
	 */
	scwin.setCurtTime = function() {
		spnCurtTime.setValue(utilLib.getCurrentDate("yyyy-MM-dd HH:mm:ss"));
	};

	/**
	 * 메뉴 버튼 클릭 event
	 */
	scwin.menuBtn = function() {
		$(".wrap_ecs_menu ul li .w2anchor2").click(function() {
			$(".wrap_ecs_menu ul li .w2anchor2").parent().removeClass("on");
			$(this).parent().addClass("on");
		});
		$(".wrap_ecs_menu ul li:nth-child(1) .w2anchor2").click(function() {
			$(".wrap_ecs_main > div").hide();
			$(".wrap_ecs_main .main_01").show();
			dmaSearchParam.set("nttClsCd", "");

			// 공지사항 게시판 조회
			// scwin.selectNttMng("ECS0000000001", 0, 3);
		});
		$(".wrap_ecs_menu ul li:nth-child(2) .w2anchor2").click(function() {
			$(".wrap_ecs_main > div").hide();
			$(".wrap_ecs_main .main_02").show();
			dmaSearchParam.set("nttClsCd", "10");
			scwin.searchWdTabData();

			// 공지사항 게시판 조회
			scwin.selectNttMng("ECS0000000001", 0, 3);
		});
		$(".wrap_ecs_menu ul li:nth-child(3) .w2anchor2").click(function() {
			$(".wrap_ecs_main > div").hide();
			$(".wrap_ecs_main .main_03").show();
			dmaSearchParam.set("nttClsCd", "20");
			scwin.searchWdTabData();

			// 공지사항 게시판 조회
			scwin.selectNttMng("ECS0000000001", 0, 3);
		});
		$(".wrap_ecs_menu ul li:nth-child(4) .w2anchor2").click(function() {
			$(".wrap_ecs_main > div").hide();
			$(".wrap_ecs_main .main_04").show();
			dmaSearchParam.set("nttClsCd", "30");
			scwin.searchWdTabData();

			// 공지사항 게시판 조회
			scwin.selectNttMng("ECS0000000001", 0, 3);
		});
		$(".wrap_ecs_menu ul li:nth-child(5) .w2anchor2").click(function() {
			$(".wrap_ecs_main > div").hide();
			$(".wrap_ecs_main .main_05").show();
			dmaSearchParam.set("nttClsCd", "40");
			scwin.searchWdTabData();

			// 공지사항 게시판 조회
			scwin.selectNttMng("ECS0000000001", 0, 3);
		});
	};

	//============================================================================================
	// 공지사항
	//============================================================================================
	/**
	 * 공지사항 게시물 조회
	 * @param
	 */
	scwin.selectNttMng = function(bbsId, rnum, pageSize) {
		var nttTit = "";
		var korname = "";

		var requestData = {};
		requestData.data = {
			bbsId : bbsId,
			rnum : rnum,
			totalCount : rnum,
			pageSize : pageSize
		};

		if (dmaSearchParam.get("nttClsCd") == "10") {
			requestData.data.nttClsCd = "BBS001";
		} else if (dmaSearchParam.get("nttClsCd") == "20") {
			requestData.data.nttClsCd = "BBS002";
		} else if (dmaSearchParam.get("nttClsCd") == "30") {
			requestData.data.nttClsCd = "BBS003";
		} else if (dmaSearchParam.get("nttClsCd") == "40") {
			requestData.data.nttClsCd = "BBS004";
		}

		var option = {
			action : "/sc/ntt/retrieveNtt.do",
			reqData : requestData,
			resData : "",
			success : "scwin.selectNttMngCallback",
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);
	};

	/**
	 * 공지사항 게시물 조회 callback
	 * @param
	 */
	scwin.selectNttMngCallback = function(resBody) {
		var bbsList = resBody.data;
		var html = "";
		var objId = "";
		for (i = 0; i < bbsList.length; i++) {
			var ntt = bbsList[i];
			html += '<tr class="w2group "><td class="w2group w2tb_td w2tb_noTH"><a href="#" onclick="scwin.nttTitClick('
				+ ntt.nttNo
				+ '); return false;"><span class="w2span ">'
				+ ntt.nttTit
				+ '</span></a></td><td class="w2group w2tb_td right w2tb_noTH"><span class="w2span ">'
				+ ntt.frstRegistDt.substring(0, 10).replace(/\-/gi, ".")
				+ "</span></td></tr>";
		}

		if (dmaSearchParam.get("nttClsCd") == "10") {
			objId = "grpHanNttList";
		} else if (dmaSearchParam.get("nttClsCd") == "20") {
			objId = "grpNakNttList";
		} else if (dmaSearchParam.get("nttClsCd") == "30") {
			objId = "grpGeumNttList";
		} else if (dmaSearchParam.get("nttClsCd") == "40") {
			objId = "grpYsumNttList";
		} else {
			objId = "grpAllNttList";
		}

		$p.$("#" + objId + " tr").remove();
		$(html).appendTo("#" + objId);
	};

	/**
	 * 공지사항 게시물 클릭
	 */
	scwin.nttTitClick = function(nttNo) {
		top.comLib.initBoard($p, "ntt,01,ECS0000000001," + nttNo);
	};

	/**
	 * 데이터들을 조회한다.
	 */
	scwin.searchDatas = function() {
		// SMP
		scwin.searchRollingData();

		// 전주기 현황 계획/건설/관리/폐기 데이터 조회
		scwin.searchRecyclePbmeData();
		// 전주기 현황 정산-생산/소비 데이터 조회
		scwin.searchCyclePC();

		// RE100 데이터 조회
		//scwin.searchChartRe100FlflRt();
		// 탄소중립 현황 데이터 조회-위탁사업장포함
		scwin.searchCbnNtrltCsmtBplcData();
		// 탄소중립 현황 데이터 조회
		scwin.searchCbnNtrltData();
		// 유역현황도 데이터 조회
		scwin.searchBasinSttusData();

		// 전주기 현황 정산-발전수익 데이터 조회, 전주기 현황 정산-기타수익 데이터 조회, 전주기 현황 정산-소비정산 데이터 조회, 차트 생산 데이터 조회, 차트 소비 데이터 조회
		scwin.searchPC();
	};

	//============================================================================================
	// SMP
	//============================================================================================
	/**
	 * SMP/K-Water 판매단가 데이터를 조회한다.
	 */
	scwin.searchRollingData = function() {
		// K-Water 단가 라벨 변경
		var strtDt = utilLib.getCurrentDate("yyyyMMdd");
		var currentYear = strtDt.substr(2, 2);
		spnRollingLabel.setLabel(currentYear);

		var option = {
			action : "ec/main/retrieve-sle-upc.do" +
				"?strtDt=" + strtDt,
			method : "get",
			resData : "",
			success : "scwin.searchRollingDataCallBack",
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);

		var option = {
			action : "ec/main/retrieve-kwater-upc.do" +
				"?strtDt=" + strtDt,
			method : "get",
			resData : "",
			success : "scwin.searchRollingDataCallBack",
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);
	};

	/**
	 * SMP/K-Water 판매단가 데이터 조회 콜백
	 */
	scwin.searchRollingDataCallBack = function(resbody) {
		var rollingData = resbody.data;

		if (rollingData.find(obj => obj.systLimitUpc)) {
			spnMainRollingData1.setLabel(ecsLib.dsplFrmt((rollingData.find(obj => obj.systLimitUpc || 0).systLimitUpc)));
		} else if (rollingData.find(obj => obj.elyrsUpcVu)) {
			spnMainRollingData2.setLabel(ecsLib.dsplFrmt((rollingData.find(obj => obj.elyrsUpcVu || 0).elyrsUpcVu)));
		}

		var rollingDataEmts = document.querySelectorAll("#" + $p.getFrameId() + " .main-con-box span[id*='_spnMainRollingData']");
		for (var idx = 1; idx < rollingDataEmts.length + 1; idx++) {
			scwin.setRollingColor(idx);
		}
		if (!scwin.isEventOn) {
			setTimeout(() => {
				setInterval(() => {
					var ulLabelId = "#" + grpMainRollingLabel.getID();
					var ulDataId = "#" + grpMainRollingData.getID();
					var height = document.querySelector("#" + $p.getFrameId() + " .main-con-box .main-rolling").clientHeight - 2;
					var animateFunc = function() {
						var parentId = "#" + $(this).parent().attr("id");
						$(this).detach().appendTo(parentId).css("margin-top", "");
						if (parentId && parentId.endsWith("RollingData")) {
							scwin.setRollingColor($(this).attr("id").substr(-1));
						}
					};
					$(ulLabelId + " li:first").animate({"marginTop" : "-" + height + "px"}, 1300, animateFunc);
					$(ulDataId + " li:first").animate({"marginTop" : "-" + height + "px"}, 1300, animateFunc);
				}, 5500);
			}, 500);
			scwin.isEventOn = true;
		}
	};

	/**
	 * SMP/K-Water 판매단가 색상 설정
	 * @param idNum : ID의 마지막 숫자
	 */
	scwin.setRollingColor = function(idNum) {
		var rollingData = dltRollingData.getAllJSON();
		var sttus = false;

		switch(idNum) {
			case 1:
			case "1":
				sttus = (rollingData.find(obj => obj.iemDivId == "smpSttus") || 0).inqireIemVu >= 0 ? true : false;
				break;
			case 2:
			case "2":
				sttus = (rollingData.find(obj => obj.iemDivId == "kwSleUpcSttus") || 0).inqireIemVu >= 0 ? true : false;
				break;
		}

		if (!sttus || sttus == "false" || sttus == "down") {
			$p.getComponentById("spnMainRollingUpDown" + idNum).setValue("&#9660;&emsp;");
			$p.getComponentById("spnMainRollingUpDown" + idNum).setStyle("color", "#0082FF");
		} else {
			$p.getComponentById("spnMainRollingUpDown" + idNum).setValue("&#9650;&emsp;");
			$p.getComponentById("spnMainRollingUpDown" + idNum).setStyle("color", "#FF0024");
		}
	};

	//============================================================================================
	// 차트
	//============================================================================================
	/**
	 * 차트 생성
	 */
	// 생산량, 소비량 및 정산금액 차트
	scwin.createPCCharts = function() {
		var chartOriginalId = grpMainChartList.getOriginalID();
		Object.keys(scwin.initData.chart.displayData).forEach(source => {
			var comp = $p.getComponentById(chartOriginalId + source);
			if (source == "PC") {
				for (var idx = 1; idx <= 2; idx++) {
					var chartVars = "rMateOnLoadCallFunction=" + $p.id + "scwin.chartReadyHandlerPrdctn";
					if (idx == 2) chartVars = "rMateOnLoadCallFunction=" + $p.id + "scwin.chartReadyHandlerCnstn";
					rMateChartH5.create($p.id + "chart_" + source + "_" + idx, comp.getID() + "_" + idx, chartVars, "98%", "99%");
				}
			}
		});
	};

	// 계획, 건설, 관리, 폐기 차트
	scwin.createCyclePBMECharts = function() {
		var chartOriginalId = grpMainChartList.getOriginalID();
		Object.keys(scwin.initData.chart.displayData).forEach(source => {
			var comp = $p.getComponentById(chartOriginalId + source);
			if (source == "Plan" || source == "Cnstrc"  || source == "MngReprMntnc"  || source == "Dsuse") {
				var chartVars = "rMateOnLoadCallFunction=" + $p.id + "scwin.chartReadyHandlerAll";
				rMateChartH5.create($p.id + "chart_" + source, comp.getID(), chartVars, "98%", "90%");
			}
		});
	};

	// 생산, 소비, 정산 차트
	scwin.createCyclePCCharts = function() {
		var chartOriginalId = grpMainChartList.getOriginalID();
		Object.keys(scwin.initData.chart.displayData).forEach(source => {
			var comp = $p.getComponentById(chartOriginalId + source);
			if (source == "Prdctn" || source == "Cnstn") {
				var chartVars = "rMateOnLoadCallFunction=" + $p.id + "scwin.chartReadyHandlerPC";
				for (var idx = 1; idx <= 2; idx++) {
					var chartWidth = (idx == 2) ? "66%" : "33%";
					rMateChartH5.create($p.id + "chart_" + source + "_" + idx, comp.getID() + "_" + idx, chartVars, "98%", "99%");
				}
			} else if (source == "ElyrsErn") {
				var chartVars = "rMateOnLoadCallFunction=" + $p.id + "scwin.chartReadyHandlerAll";
				rMateChartH5.create($p.id + "chart_" + source, comp.getID(), chartVars, "98%", "90%");
			}
		});
	};

	/**
	 * RE100 차트 데이터를 조회한다.
	 */
	scwin.searchChartRe100FlflRt = function() {
		var strtDt = Number(utilLib.getCurrentDate("yyyy")) - 4;
		var endDt = utilLib.getCurrentDate("yyyy");

		var queryString = `?strtDt=${strtDt}`;
		queryString += `&endDt=${endDt}`;

		var option = {
			action : "ec/main/retrieve-re100-flfl.do" +
				queryString,
			method : "get",
			resData : dltRe100FlflRtData,
			success : "scwin.searchChartRe100FlflRtCallBack",
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);
	};

	/**
	 * RE100 차트 데이터 조회 콜백
	 */
	scwin.searchChartRe100FlflRtCallBack = function() {
		var chartVars = "rMateOnLoadCallFunction=" + $p.id + "scwin.chartReadyHandlerRe100FlflRt";
		rMateChartH5.create($p.id + "chartRe100FlflRt", grpMainChartRe100FlflRt.getID(), chartVars, "99%", "90%");
	};

	/**
	 * RE100 차트 시리즈 안쪽 수치 핸들러
	 * @param {
	 	seriesID : ID,
	 	index : 인덱스,
	 	data : 데이터 맵,
	 	values : 값
	 }
	 * @return 시리즈 안쪽 수치 내용
	 */
	scwin.re100FlflRtInsideLabelHandler = function(seriesID, index, data, values) {
		return values[1] + "%";
	};

	/**
	 * RE100 차트 시리즈 바깥쪽 수치 핸들러
	 * @param {
	 	seriesID : ID,
	 	index : 인덱스,
	 	data : 데이터 맵,
	 	values : 값
	 }
	 * @return 시리즈 바깥쪽 수치 내용
	 */
	scwin.re100FlflRtOutsideLabelHandler = function(seriesID, index, data, values) {
		return " " + values[0];
	};

	/**
	 * RE100 차트 시리즈 색상 핸들러
	 * @param {
	 	seriesID : ID,
	 	index : 인덱스,
	 	data : 데이터 맵,
	 	values : 값
	 }
	 * @return 시리즈 색상
	 */
	scwin.re100FlflRtFillHandler = function(seriesID, index, data, values) {
		if (index == (scwin.re100FlflRtChartCount - 1)) {
			return "#B2CCFF"; // 6799FF
		} else {
			return ecsLib.getSkinColors().chartSolidColor2;
		}
	};

	/**
