	/**
	 * RE100 차트 설정
	 * @param id : 차트 그룹 ID
	 */
	scwin.chartReadyHandlerRe100FlflRt = function(id) {
		var re100FlflRtChartData = dltRe100FlflRtData.getAllJSON();
		var interval = 25;
		var totalMax = re100FlflRtChartData.reduce((max, obj) => max < Number(obj.total) ? Number(obj.total) : max, 0);
		var max;
		if (totalMax < 100) {
			max = 100;
		} else {
			max = Math.round(totalMax / 100) * 100;
		}

		re100FlflRtChartData.forEach(obj => {
			obj["goal"] = max;
		});

		// spnMainChartRe100FlflRtTitleData.setValue(re100FlflRtChartData.slice(-1)[0]["total"] + "%");

		scwin.re100FlflRtChartCount = re100FlflRtChartData.length;
		var solidColor = ecsLib.getSkinColors().chartSolidColor2;

		var layoutStr = '<rMateChart backgroundColor="" cornerRadius="12">'
			+ '	<Options>'
			// + '		<Caption text="RE100 이행률" />'
			// + '		<Legend position="center" />'
			+ '	</Options>'
			+ '	<Combination3DChart showDataTips="false" cubeAngleRatio="1" columnWidthRatio="0.6">'
			+ '<backgroundElements>'
			+ '</backgroundElements>'
			+ '		<horizontalAxis>'
			+ '			<CategoryAxis id="hAxis" categoryField="re100Year" ticksBetweenLabels="true" labelJsFunction="' + $p.id + 'scwin.re100FlflRtCategoryLabelHandler" padding="0.65" />'
			+ '		</horizontalAxis>'
			+ '		<horizontalAxisRenderers>'
			+ '			<Axis3DRenderer axis="{hAxis}" visible="true" canDropLabels="false" showLine="false" tickPlacement="none" labelGap="7" fontSize="12" fontWeight="bolder" />'
			+ '		</horizontalAxisRenderers>'
			+ '		<verticalAxis>'
			+ '			<LinearAxis id="vAxis" maximum="' + (max + (interval / 1.3)) + '" interval="' + interval + '" labelJsFunction="' + $p.id + 'scwin.re100FlflRtLinearLabelHandler" />'
			+ '		</verticalAxis>'
			+ '		<verticalAxisRenderers>'
			+ '			<Axis3DRenderer axis="{vAxis}" visible="false" />'
			+ '		</verticalAxisRenderers>'
			+ '		<series>'
			+ '			<VTarget3DResultSeries itemRenderer="CylinderItemRenderer" labelPosition="inside" labelAlign="center" insideLabelJsFunction="' + $p.id + 'scwin.re100FlflRtInsideLabelHandler"'
			+ '				outsideLabelJsFunction="' + $p.id + 'scwin.re100FlflRtOutsideLabelHandler" fillJsFunction="' + $p.id + 'scwin.re100FlflRtFillHandler"'
			+ '				color="#222222" font-weight="bold" yField="total" displayName="이행률" columnWidthRatio="0.5">'
			+ '				<fill>'
			+ '					<SolidColor color="' + solidColor + '" />'
			+ '				</fill>'
			+ '				<showDataEffect>'
			+ '					<SeriesInterpolate />'
			+ '				</showDataEffect>'
			+ '			</VTarget3DResultSeries>'
			+ '			<VTarget3DGoalSeries itemRenderer="CylinderTargetItemRederer" labelAlign="center"'
			+ '				color="#222222" font-weight="bold" yField="goal" displayName="100%" columnWidthRatio="0.5">'
			+ '				<fill>'
			+ '					<SolidColor color="#B2CCFF" alpha="0.1" />'
			+ '				</fill>'
			+ '				<showDataEffect>'
			+ '					<SeriesInterpolate />'
			+ '				</showDataEffect>'
			+ '			</VTarget3DGoalSeries>'
			+ '		</series>'
			+ '	</Combination3DChart>'
			+ '</rMateChart>';

		document.getElementById(id).setLayout(layoutStr);
		document.getElementById(id).setData(re100FlflRtChartData);
		//ecsLib.chartReload(id);
	};

