	/**
	 * 탄소중립현황 데이터 조회 콜백
	 */
	scwin.searchCbnNtrltDataCallBack = function() {
		var checkValue = cbxCbnNtrltCsmtBplc.getValue();
		if (checkValue == "Y") {
			var cbnNtrltData = dltCbnNtrltCsmtBplcData.getAllJSON();
		} else {
			var cbnNtrltData = dltCbnNtrltData.getAllJSON();
		}

		// var cbnNtrlt = document.querySelector("#" + $p.getFrameId() + " .main-con-box .main-cbn-ntrlt");
		// var bar = cbnNtrlt.querySelector("#" + $p.getFrameId() + " .cbn-ntrlt-bar");
		// var rqty = cbnNtrlt.querySelector("#" + $p.getFrameId() + " .cbn-ntrlt-rqty");
		// var dsqty = cbnNtrlt.querySelector("#" + $p.getFrameId() + " .cbn-ntrlt-dsqty");
		var cbnNtrlt = document.querySelector("#" + $p.getFrameId() + " .main-con-box .main-cbn-ntrlt-box");
		var bar = cbnNtrlt.querySelector("#" + $p.getFrameId() + " .main-cbn-ntrlt-stick");
		var rqty = cbnNtrlt.querySelector("#" + $p.getFrameId() + " .main-cbn-ntrlt-earth");
		var dsqty = cbnNtrlt.querySelector("#" + $p.getFrameId() + " .main-cbn-ntrlt-pollution");
		var cbnTextEmts = cbnNtrlt.querySelectorAll("#" + $p.getFrameId() + " .main-cbn-ntrlt-data-box-data");
		var cbnPercentEmt = document.querySelector("#" + $p.getFrameId() + " .main-con-box .main-box-title-data");

		var keyframes = [
			{"filter" : "blur(0.15rem)"},
			{"filter" : "blur(0.2rem)"},
			{"filter" : "blur(0.15rem)"},
			{"filter" : "blur(0.05rem)"},
			{"filter" : "blur(0rem)"}
		];

		var keyframes = [
			{"filter" : "opacity(0)"},
			{"filter" : "opacity(0.25)"},
			{"filter" : "opacity(0.5)"},
			{"filter" : "opacity(0.75)"},
			{"filter" : "opacity(1)"}
		];

		var options = {
			"delay" : 50,
			"duration" : 2000,
			"easing" : "ease",
			"iterations" : "1",
			"fill" : "none"
		};

		for (emt of cbnTextEmts) {
			emt.style.transformStyle = "preserve-3d";
			emt.animate(keyframes, options);
		}
		if (cbnPercentEmt) {
			cbnPercentEmt.style.transformStyle = "preserve-3d";
			cbnPercentEmt.animate(keyframes, options);
		}

		var existStyleTime = 0;
		for (var emt of [bar, rqty, dsqty]) {
			if (!existStyleTime && emt.style.transform) {
				existStyleTime = 100;
			}
			emt.style.transformStyle = "preserve-3d";
			emt.style.transform = "";
			emt.style.transition = "";
		}

		var nowYear = utilLib.addMonth(utilLib.getCurrentDate("yyyyMM"), -2).substr(0, 4);
		var rqtyData = (cbnNtrltData.find(obj => obj.inqireDe == nowYear && obj.iemDivId == "rqtySum") || 0).inqireIemVu;
		var dsqtyData = (cbnNtrltData.find(obj => obj.inqireDe == nowYear && obj.iemDivId == "dsqtySum") || 0).inqireIemVu;
		var acmtrtData = (cbnNtrltData.find(obj => obj.inqireDe == nowYear && obj.iemDivId == "acmtrt") || 0).inqireIemVu;

		// 탄소중립현황 박스 안 데이터 값 설정_240126
		spnMainChartCbnNtrltData.setLabel(ecsLib.dsplFrmt(acmtrtData, 0));
		// info 날짜 설정_240131
		var ym = utilLib.addMonth(utilLib.getCurrentDate("yyyyMM"), -2);

		spnCbnNtrltYearLabel.setLabel(ym.substr(0, 4));
		spnCbnNtrltMonthLabel.setLabel(ym.substr(4, 2));

		var styles = {};
		styles.rotate = 0;
		styles.bar = {
			"emt" : bar,
			"translateX" : 0,
			"translateY" : 0,
		};
		styles.rqty = {
			"emt" : rqty,
			"translateX" : 0,
			"translateY" : 0,
		};
		styles.dsqty = {
			"emt" : dsqty,
			"translateX" : 0,
			"translateY" : 0,
		};

		// 달성률로 시소 기울기
		if (rqtyData != undefined && dsqtyData != undefined && acmtrtData != undefined) {
			var rqtyPer = Math.abs(Number(String(rqtyData).replaceAll(",", ""))) / (Math.abs(Number(String(rqtyData).replaceAll(",", ""))) + parseFloat(String(dsqtyData).replaceAll(",", "")));

			if (0.5 < rqtyPer) {
				styles.rotate = -1.5;
				// styles.bar.translateX = -1;
				// 24.01.03 돌아가는 느낌으로 인해 0으로 변경
				styles.bar.translateX = 0;
				styles.bar.translateY = 8;
				styles.rqty.translateX = -4.5;
				styles.rqty.translateY = 0.5;
				styles.rqty.scale = 1.07;
				styles.dsqty.translateX = -2.5;
				styles.dsqty.translateY = -2;
				styles.dsqty.scale = 0.93;
			} else if (rqtyPer < 0.5) {
				styles.rotate = 1.5;
				// styles.bar.translateX = -0.5;
				// 24.01.03 돌아가는 느낌으로 인해 0으로 변경
				styles.bar.translateX = 0;
				styles.bar.translateY = -9.5;
				styles.rqty.translateX = -0.5;
				styles.rqty.translateY = -1.5;
				styles.rqty.scale = 0.93;
				styles.dsqty.translateX = 2;
				styles.dsqty.translateY = 1;
				styles.dsqty.scale = 1.07;
			}

			if ((0 <= rqtyPer && rqtyPer < 0.4) || (1 >= rqtyPer && rqtyPer > 0.6)) {
				styles.rotate *= 2;
				styles.bar.translateX *= 2;
				styles.bar.translateY *= 2;
				styles.rqty.translateX *= 2;
				styles.rqty.translateY *= 2;
				styles.dsqty.translateX *= 2;
				styles.dsqty.translateY *= 2;
			}
		}

		setTimeout(() => {
			var selector = ".main-con-box .main-cbn-ntrlt-scale .main-cbn-ntrlt-data-box.main-cbn-ntrlt-data-box-";
			var sign = "=";
			if (styles.rotate > 0) {
				sign = "<";
			} else if (styles.rotate < 0) {
				sign = ">";
			} else if (rqtyPer == undefined) {
				sign = "-";
			}
			spnMainChartCbnNtrltTitleData.setLabel(sign);
			// grpMainCbnNtrltScaleSvg.setMainCbnNtrltData(ecsLib.dsplFrmt(acmtrtData || 0, 0));
			$p.getComponentById(document.querySelector(selector + "rqty > span.main-cbn-ntrlt-data-box-data").id).setLabel(ecsLib.dsplFrmt(rqtyData || 0, 0));
			$p.getComponentById(document.querySelector(selector + "dsqty > span.main-cbn-ntrlt-data-box-data").id).setLabel(ecsLib.dsplFrmt(dsqtyData || 0, 0));

			for (var key of Object.keys(styles)) {
				if (key != "rotate") {
					var transformStyle = `rotate(${styles.rotate}deg) translateY(${styles[key].translateY}%) translateX(${styles[key].translateX}%)`;
					transformStyle += styles[key]["scale"] ? ` scale(${styles[key]["scale"]})` : "";
					styles[key]["emt"].style.transformStyle = "preserve-3d";
					styles[key]["emt"].style.transform = transformStyle;
					styles[key]["emt"].style.transition = "all ease 2s 0.15s";
				}
			}
		}, existStyleTime || 500);

		/*
		// 달성률로 시소 기울기
		var rqtyPer = Math.abs(Number(rqtyData.replaceAll(",", ""))) / (Math.abs(Number(rqtyData.replaceAll(",", ""))) + parseFloat(dsqtyData.replaceAll(",", "")));
		var rotate = 0;
		var translateX = 0;
		var translateY = 0;
		if (0.5 < rqtyPer) {
			rotate = -1.5;
			translateX = -0.5;
		} else if (rqtyPer < 0.5) {
			rotate = 1.5;
			translateX = 1.1;
		}

		if (rqtyPer > 0.4 || 0.6 > rqtyPer) {
			rotate *= 2;
			translateX *= 2;
		}
		if (rqtyPer > 0.5) {
			translateY = rotate * -2.5;
		} else if (0.5 > rqtyPer) {
			translateY = rotate * -2;
		}

		setTimeout(() => {
			var selector = ".main-con-box .main-cbn-ntrlt .main-cbn-ntrlt-data-box.main-cbn-ntrlt-data-box-";
			// spnMainChartCbnNtrltTitleData.setLabel(acmtrtData);
			$p.getComponentById(document.querySelector(selector + "rqty > span.main-cbn-ntrlt-data-box-data").id).setLabel(ecsLib.dsplFrmt(rqtyData));
			$p.getComponentById(document.querySelector(selector + "dsqty > span.main-cbn-ntrlt-data-box-data").id).setLabel(ecsLib.dsplFrmt(dsqtyData));

			for (var emt of [bar, rqty, dsqty]) {
				emt.style.transformStyle = "preserve-3d";
				emt.style.transform = `rotate(${rotate}deg) translateY(${translateY}%) translateX(${translateX}%)`;
				emt.style.transition = "all ease 2s 0.15s";
			}
		}, existStyleTime || 500);
		*/
	};

