	/**
	 * 데이터 차트(5개년) 시리즈 바깥쪽 수치 핸들러
	 * @param {
	 	seriesID : ID,
	 	index : 인덱스,
	 	data : 데이터 맵,
	 	values : 값
	 }
	 * @return 시리즈 바깥쪽 수치 내용
	 */
	//계획 건설 폐기 (return 건, MW, 억원)
	scwin.PCDOutsideLabelHandler = function(seriesID, index, data, values) {
		var strLabel = "";
		if (seriesID == "etcErn") {
			strLabel = "건";
		} else if (seriesID == "etcErn2") {
			strLabel = "MW";
		} else if (seriesID == "etcErn3") {
			strLabel = "억원";
		}
		return ecsLib.dsplZeroFrmt(values[1], 0) + "<br>" + strLabel;
	};

	//생산 소비 (return MWh, GWh)
	scwin.PCOutsideLabelHandler = function(seriesID, index, data, values) {
		var strLabel = "GWh";
		/*
		if (seriesID == "etcErn") {
			strLabel = "MWh";
		} else if (seriesID == "etcErn2" || seriesID == "etcErn3") {
			strLabel = "GWh";
		}
		*/
		return ecsLib.dsplZeroFrmt(values[1], 0) + "<br>" + strLabel;
	};

	//관리 (return 건)
	scwin.MOutsideLabelHandler = function(seriesID, index, data, values) {
		var strLabel = "건";
		return ecsLib.dsplZeroFrmt(values[1], 0) + "<br>" + strLabel;
	};

	//정산 (return 억원)
	scwin.EOutsideLabelHandler = function(seriesID, index, data, values) {
		var strLabel = "억원";
		return ecsLib.dsplZeroFrmt(values[1], 0) + "<br>" + strLabel;
	};

	/**
	* 계획/건설/관리/정산/폐기 데이터 차트(5개년) 설정
	 * @param id : 차트 그룹 ID
	 */
	scwin.chartReadyHandlerAll = function(id) {
		var strtDt = utilLib.getCurrentDate("yyyy") - 4;
		var endDt = utilLib.getCurrentDate("yyyy");

		var chartId = id;
		var source = id.split("_");
		var bNum = Number(source[source.length - 1]);
		source = bNum > 0 ? source[source.length - 2] : source[source.length - 1];
		bNum = bNum > 0 ? bNum : "";
		var title = Object.keys(scwin.initData.chart.displayData[source])[0];
		var title2 = scwin.initData.chart.displayData[source][title];
		scwin.initData.thisLabel = source;
		var chartList = [];

		// 차트 좀 내려줌
		document.getElementById($p.id + "chart_" + source).style.top = "0.75rem";

		var setLableHandler = "";

		// 계획, 건설, 관리, 폐기
		if (source == "Plan" || source == "Cnstrc" || source == "MngReprMntnc" || source == "Dsuse") {
			setLableHandler = "scwin.PCDOutsideLabelHandler"; // 계획 건설 폐기
			if (source == "MngReprMntnc") setLableHandler = "scwin.MOutsideLabelHandler"; // 관리

			var etcErnData = dltCyclePbmeData.getAllJSON();
			var etcErn;
			var etcErn2;
			var etcErn3;

			if (source == "Plan") {
				etcErn = "planComptCnt";
				etcErn2 = "planComptEqpCpcty";
				etcErn3 = "planComptAmt";
			} else if (source == "Cnstrc") {
				etcErn = "cnstrcComptCnt";
				etcErn2 = "cnstrcComptEqpCpcty";
				etcErn3 = "cnstrcComptAmt";
			} else if (source == "MngReprMntnc") {
				etcErn = "mngReprMntnc";
				etcErn2 = "mngRemt";
				etcErn3 = "mngChckMntnc";
			} else if (source == "Dsuse") {
				etcErn = "dsuseComptCnt";
				etcErn2 = "dsuseComptEqpCpcty";
				etcErn3 = "dsuseComptAmt";
			}

			for (var idx = strtDt; idx <= endDt; idx++) {
				chartList.push({
					"year" : idx,
					"etcErn" : Number(ecsLib.dsplZeroFrmt((etcErnData.find(obj => obj.inqireDe == idx && obj.iemDivId == etcErn) || 0).inqireIemVu, 0).replaceAll(",", "")),
					"etcErn2" : Number(ecsLib.dsplZeroFrmt((etcErnData.find(obj => obj.inqireDe == idx && obj.iemDivId == etcErn2) || 0).inqireIemVu, 0).replaceAll(",", "")),
					"etcErn3" : Number(ecsLib.dsplZeroFrmt((etcErnData.find(obj => obj.inqireDe == idx && obj.iemDivId == etcErn3) || 0).inqireIemVu, 0).replaceAll(",", ""))
				});
			}
		// 정산
		} else if (source == "ElyrsErn") {
			var etcErnData1 = dltElyrsErnData.getAllJSON();
			var etcErnData2 = dltEtcErnData.getAllJSON();
			var etcErnData3 = dltCnstnExcclcData.getAllJSON();
			setLableHandler = "scwin.EOutsideLabelHandler"; // 정산

			for (var idx = strtDt; idx <= endDt; idx++) {
				chartList.push({
					"year" : idx,
					"etcErn" : Number(ecsLib.dsplZeroFrmt((etcErnData1.reduce((sum, obj) => obj.inqireDe == idx && obj.iemDivId != "total" && !obj.iemDivId.endsWith("Inqire") && obj.inqireIemVu ? sum + obj.inqireIemVu : sum, 0) || 0), 0).replaceAll(",", "")),
					"etcErn2" : Number(ecsLib.dsplZeroFrmt((etcErnData2.reduce((sum, obj) => obj.inqireDe == idx && obj.iemDivId != "total" && !obj.iemDivId.endsWith("Inqire") && obj.inqireIemVu ? sum + obj.inqireIemVu : sum, 0) || 0), 0).replaceAll(",", "")),
					"etcErn3" : Number(ecsLib.dsplZeroFrmt((etcErnData3.reduce((sum, obj) => obj.inqireDe == idx && obj.iemDivId != "total" && !obj.iemDivId.endsWith("Inqire") && obj.inqireIemVu ? sum + obj.inqireIemVu : sum, 0) || 0), 0).replaceAll(",", ""))
				});
			}
		}

		var maxData = ecsLib.chartDataTotalAmt(chartList, ["etcErn", "etcErn2", "etcErn3"]);
		var prdctnUnit = Math.max(scwin.initData.chart.prdctnUnit, Math.pow(10, String(maxData.toFixed(0)).length - 2));
		var interval = Math.ceil((maxData / scwin.initData.chart.prdctnIntervalCount) / prdctnUnit) * prdctnUnit;

		var fillColor = "#41B2E6";
		var fillColor2 = "#4453A8";
		var fillColor3 = "#F9BD03";

		var layoutStr =
			'<rMateChart backgroundColor="" cornerRadius="12">'
			+ '	<Options>'
			// + '		<Caption text="' + title + ' ' + /*title2 + */'" textAlign="center" paddingRight="9.6" paddingBottom="9.6" paddingLeft="9.6" fontWeight="bold" fontSize="1rem" />'
			+ '	</Options>'
			+ '	<NumberFormatter id="numFmt" useThousandsSeparator="true" />'
			+ '	<Column2DChart showDataTips="true" columnWidthRatio="0.6" dataTipDisplayMode="axis" maxColumnWidth="25">'
			+ '		<horizontalAxis>'
			+ '			<CategoryAxis id="hAxis" categoryField="year" />'
			+ '		</horizontalAxis>'
			+ '		<horizontalAxisRenderers>'
			+ '			<Axis3DRenderer axis="{hAxis}" labelGap="9" />'
			+ '		</horizontalAxisRenderers>'
			+ '		<verticalAxis>'
			+ '			<LinearAxis id="vAxis" interval="' + interval + '" formatter="{numFmt}" />'
			+ '		</verticalAxis>'
			+ '		<series>'
			+ '			<Column2DSeries id="etcErn" halfWidthOffset="5" labelPosition="outside" fontWeight="bold" displayName="' + title2[0] + '" yField="etcErn" outsideLabelJsFunction="' + $p.id + setLableHandler + '">' // fillJsFunction="' + $p.id + 'scwin.fillHandler">'
			+ '				<fill>'
			+ '					<SolidColor color="' + fillColor + '" />'
			+ '				</fill>'
			+ '				<showDataEffect>'
			+ '					<SeriesInterpolate />'
			+ '				</showDataEffect>'
			+ '			</Column2DSeries>'
			+ '			<Column2DSeries id="etcErn2" halfWidthOffset="5" labelPosition="outside" fontWeight="bold" displayName="' + title2[1] + '" yField="etcErn2" outsideLabelJsFunction="' + $p.id + setLableHandler + '">' // fillJsFunction="' + $p.id + 'scwin.fillHandler">'
			+ '				<fill>'
			+ '					<SolidColor color="' + fillColor2 + '" />'
			+ '				</fill>'
			+ '				<showDataEffect>'
			+ '					<SeriesInterpolate />'
			+ '				</showDataEffect>'
			+ '			</Column2DSeries>'
			+ '			<Column2DSeries id="etcErn3" halfWidthOffset="5" labelPosition="outside" fontWeight="bold" displayName="' + title2[2] + '" yField="etcErn3" outsideLabelJsFunction="' + $p.id + setLableHandler + '">' // fillJsFunction="' + $p.id + 'scwin.fillHandler">'
			+ '				<fill>'
			+ '					<SolidColor color="' + fillColor3 + '" />'
			+ '				</fill>'
			+ '				<showDataEffect>'
			+ '					<SeriesInterpolate />'
			+ '				</showDataEffect>'
			+ '			</Column2DSeries>'
			+ '		</series>'
			+ '	</Column2DChart>'
			+ '</rMateChart>';

		document.getElementById(id).setLayout(layoutStr);
		document.getElementById(id).setData(chartList);
	};

	/**
	 * 생산/소비 데이터 차트(5개년) 시리즈 색상 핸들러
