	 	data : 데이터 맵,
	 	values : 값
	 }
	 * @return 시리즈 색상
	 */
	scwin.pcFillHandler = function(seriesID, index, data, values) {
		var inqireDe = utilLib.getCurrentDate("yyyy");
		var years = data.Year;
		var color = ["#0674d4", "#2482e0", "#3d98ea", "#4ba1ef", "#65adec"];
		var idx = Number(inqireDe) - Number(years);

		return color[idx];
	};

