	/**
	* 생산/소비 데이터 차트(5개년) 설정
	 * @param id : 차트 그룹 ID
	 */
	scwin.chartReadyHandlerPC = function(id) {
		var chartId = id;
		var source = id.split("_");
		var bNum = Number(source[source.length - 1]);
		source = bNum > 0 ? source[source.length - 2] : source[source.length - 1];
		bNum = bNum > 0 ? bNum : "";
		var title = Object.keys(scwin.initData.chart.displayData[source])[0];
		var title2 = scwin.initData.chart.displayData[source][title];
		scwin.initData.thisLabel = source;
		var chartList = [];
		var layoutStr = "";

		var dataList = dltPCData.getAllJSON();
		var strtDt = utilLib.getCurrentDate("yyyy") - 4;
		var endDt = utilLib.getCurrentDate("yyyy");

		var etcErn = "de" + source;
		var etcErn2 = "mt" + source;
		var etcErn3 = "yy" + source;

		var fillColor = "#41B2E6";
		var fillColor2 = "#4453A8";
		var fillColor3 = "#F9BD03";

		// 차트 2개 생산, 소비 연 데이터
		// bNum : 1 (왼쪽 차트), 2 (오른쪽 차트)
		if (bNum == 1) {
			var setLableHandler = "scwin.PCOutsideLabelHandler"; // 생산 소비

			for (var idx = strtDt; idx <= endDt; idx++) {
				chartList.push({
					"year" : idx,
					"etcErn" : Number(ecsLib.dsplZeroFrmt((dataList.find(obj => obj.inqireDe == idx && obj.iemDivId == etcErn3) || 0).inqireIemVu, 0).replaceAll(",", ""))
				});
			}

			var maxData = ecsLib.chartDataTotalAmt(chartList, "etcErn");
			var prdctnUnit = Math.max(scwin.initData.chart.prdctnUnit, Math.pow(10, String(maxData.toFixed(0)).length - 2));
			var interval = Math.ceil((maxData / scwin.initData.chart.prdctnIntervalCount) / prdctnUnit) * prdctnUnit;
			layoutStr =
				'<rMateChart backgroundColor="" cornerRadius="12">'
				+ '	<Options>'
			//	+ '		<Caption text="' + title + ' ' + /*title2 + */'" textAlign="center" paddingRight="9.6" paddingBottom="9.6" paddingLeft="9.6" fontWeight="bold" fontSize="1rem" />'
				+ '		<Legend position="bottom" />'
				+ '	</Options>'
				+ '	<NumberFormatter id="numFmt" useThousandsSeparator="true" />'
				+ '	<Column2DChart showDataTips="true" dataTipDisplayMode="axis" maxColumnWidth="25" columnWidthRatio="0.9">'
				+ '		<horizontalAxis>'
				+ '			<CategoryAxis id="hAxis" categoryField="year" />'
				+ '		</horizontalAxis>'
				+ '		<horizontalAxisRenderers>'
				+ '			<Axis3DRenderer axis="{hAxis}" labelGap="9" />'
				+ '		</horizontalAxisRenderers>'
				+ '		<verticalAxis>'
				+ '			<LinearAxis id="vAxis" interval="' + interval + '" formatter="{numFmt}" title="GWh" />'
				+ '		</verticalAxis>'
				+ '		<series>'
				+ '			<Column2DSeries id="etcErn" halfWidthOffset="5" labelPosition="outside" fontWeight="bold" displayName="' + title2[0] + '" yField="etcErn" outsideLabelJsFunction="' + $p.id + setLableHandler + '">' // fillJsFunction="' + $p.id + 'scwin.fillHandler">'
				+ '				<fill>'
				+ '					<SolidColor color="' + fillColor + '" />'
				+ '				</fill>'
				+ '				<showDataEffect>'
				+ '					<SeriesInterpolate />'
				+ '				</showDataEffect>'
				+ '			</Column2DSeries>'
				+ '		</series>'
				+'		<verticalAxisRenderers>'
				+'			<Axis2DRenderer axis="{vAxis}" placement="left" verticalAxisTitleAlignment="vertical" titleGap="0" canDropLabels="false" showLine="false"/>'
				+'		</verticalAxisRenderers>'
				+ '	</Column2DChart>'
				+ '</rMateChart>';
			} else {
				var maxData = 0;
				var minData = 0;
				var ym = utilLib.addMonth(utilLib.getCurrentDate("yyyyMM"), -11);

				// 최근 12개월 월 데이터_1006
				for (var mon = 0; mon < 12; mon++) {
					var yearMonth = utilLib.addMonth(ym, mon);

					var data = (dataList.find(obj => obj.inqireDe == yearMonth && obj.iemDivId == etcErn2) || 0).inqireIemVu;
					if (data > maxData) {
						maxData = data;
					}
					if (data < minData) {
						minData = data;
					}
					if (source == "Prdctn") {
						chartList.push({"Year" : yearMonth, "Month" : "월 생산량(GWh)", "Data" : Number(ecsLib.dsplZeroFrmt(data, 0).replaceAll(",", ""))});
					} else if (source == "Cnstn") {
						chartList.push({"Year" : yearMonth, "Month" : "월 소비량(GWh)", "Data" : Number(ecsLib.dsplZeroFrmt(data, 0).replaceAll(",", ""))});
					}
				}

				if (minData < 0) {
					maxData = maxData + Math.abs(minData);
				}

				var minMonth = chartList[0].Year;
				var maxMonth = chartList[11].Year;
				var diffYear = minMonth.substr(0, 4) != maxMonth.substr(0, 4) ? true : false;

				var prdctnUnit = Math.max(scwin.initData.chart.prdctnUnit, Math.pow(10, String(maxData.toFixed(0)).length - 2));
				var interval = Math.ceil((maxData / scwin.initData.chart.prdctnIntervalCount) / prdctnUnit) * prdctnUnit;

				// 라인 차트 생성_1006
				layoutStr =
				'<rMateChart backgroundColor="" cornerRadius="12">'
				+ '	<Options>'
			//	+ '		<Caption text="그룹 테스트" textAlign="center" paddingRight="9.6" paddingBottom="9.6" paddingLeft="9.6" fontWeight="bold" fontSize="1rem" />'
				+ '		<Legend position="bottom" />'
				+ '	</Options>'
				+ '	<NumberFormatter id="numFmt" useThousandsSeparator="true" />'
				+ '	<Line2DChart showDataTips="true" dataTipJsFunction="' + $p.id + 'scwin.pcDatatipHandler" columnWidthRatio="1" dataTipDisplayMode="axis" maxColumnWidth="25">'
				+ '		<horizontalAxis>'
				+ '			<CategoryAxis id="hAxis" categoryField="Year" labelJsFunction="' + $p.id + 'scwin.pcCategoryLabelHandler" />'
				+ '		</horizontalAxis>'
				+ '		<horizontalAxisRenderers>'
				+ '			<Axis3DRenderer axis="{hAxis}" labelGap="9" />'
				+ '		</horizontalAxisRenderers>'
				+ '		<verticalAxis>'
				+ '			<LinearAxis id="vAxis" interval="' + interval + '" formatter="{numFmt}" title="GWh"/>'
				+ '		</verticalAxis>'
				+ '		<series>'
				+ '			<Line2DSeries yField="Data" radius="5" color="#222222" fill="#FFFFFF" itemRenderer="CircleItemRenderer" labelPosition="up" displayName="' + title2[1] + '">'
			//	+ '				<verticalAxis>'
			//	+ '					<LinearAxis id="vAxisR" interval="' + rightInterval + '" baseAtZero="false" maximum="' + rightMaximumData + '" minimum="' + rightMinimumData + '" />'
			//	+ '				</verticalAxis>'
				+ '				<lineStroke>'
				+ '					<Stroke color="#83DCCE" weight="3"/>'
				+ '				</lineStroke>'
				+ '				<stroke>'
				+ '					<Stroke color="#219D9D" weight="2"/>'
				+ '				</stroke>'
				+ '				<showDataEffect>'
				+ '					<SeriesInterpolate />'
				+ '				</showDataEffect>'
				+ '			</Line2DSeries>'
				+ '		</series>'
				+'		<verticalAxisRenderers>'
				+'			<Axis2DRenderer axis="{vAxis}" placement="left" verticalAxisTitleAlignment="vertical" titleGap="0" canDropLabels="false" showLine="false"/>'
				+'		</verticalAxisRenderers>'
		if (diffYear) {
			layoutStr += '<backgroundElements>'
				+ '			<GridLines/>'
				+ '			<AxisMarker>'
				+ '				<ranges>'
				+ '					<AxisRange startValue="' + minMonth + '" endValue="' + minMonth.substr(0, 4) + '12" startRangePosition="left" endRangePosition="right" horizontal="false">'
				+ '						<fill>'
				+ '							<SolidColor color="#CCCCCC" alpha="0.3"/>'
				+ '						</fill>'
				+ '					</AxisRange>'
				+ '				</ranges>'
				+ '			</AxisMarker>'
				+ '		</backgroundElements>';
		}
		layoutStr += '	</Line2DChart>'
				+ '</rMateChart>';
		}

		document.getElementById(id).setLayout(layoutStr);
		document.getElementById(id).setData(chartList);
	};

	/**
	 * 생산, 생산정산 차트 X축 라벨 핸들러
