	/**
	 * 전력 생산량/전력 소비량 및 정산금액 itemClick 핸들러
	 * @param {
	 	seriesID : ID,
	 	displayText : tooltip display data,
	 	index : 인덱스,
	 	data : 데이터 맵,
	 	values : 값
	 }
	 * @return 시리즈 색상
	 */
	scwin.chartItemClickHandler = function(seriesId, displayText, index, data, values) {
		var targetParentMenuId = "";
		var targetMenuId = "";
		var param = {};
		var ym = utilLib.addMonth(utilLib.getCurrentDate("yyyyMM"), -2);

		if (displayText.includes("생산량")) {
			targetParentMenuId = "ECSPN000000";
			targetMenuId = "ECSPN200000";
			param.setcscDivCd = scwin.initData.setcscDivCd[data.name];

			param.year = ym.substr(0, 4);
			param.month = ym.substr(4, 2);
		} else if (displayText.includes("수익금")) {
			targetParentMenuId = "ECSCL000000";
			targetMenuId = "ECSCL110000";
			param.setcscDivCd = scwin.initData.setcscDivCd[data.name] == 21 ? 20 : scwin.initData.setcscDivCd[data.name];
			param.year = ym.substr(0, 4);
			param.type = "Y";
		} else if (displayText.includes("소비량") || displayText.includes("정산금")) {
			targetParentMenuId = "ECSCN000000";
			targetMenuId = "ECSCN100000";
			param.year = ym.substr(0, 4);
			param.type = "Y";
		} else {
			return;
		}

		ecsLib.chartMenuClickEvent(
			targetParentMenuId,
			targetMenuId,
			param
		);
	};

	/**
	* 생산, 생산정산 차트 설정
	 * @param id : 차트 그룹 ID
	 */
	scwin.chartReadyHandlerPrdctn = function(id) {
		var prdctnChartData = dltPrdctnData.getAllJSON();
		var prdctnExcclcChartData = dltElyrsErnData.getAllJSON();
		var year = utilLib.addMonth(utilLib.getCurrentDate("yyyyMM"), -2).substr(0, 4);
		var chartList = [];
		Object.keys(scwin.initData.prdctnDisplayData).forEach(source => {
			var prdctnData = prdctnChartData.filter(obj => obj.inqireDe == year && obj.elcpwstnClsNm.endsWith(scwin.initData.prdctnDisplayData[source])).reduce((sum, obj) => sum + Number(obj.inqireIemVu), 0);
			var prdctnExcclcData = prdctnExcclcChartData.filter(obj => obj.inqireDe == year && obj.iemDivId.endsWith(source.toLowerCase() + "Inqire")).reduce((sum, obj) => sum + Number(obj.inqireIemVu), 0);
			chartList.push({
				"name" : scwin.initData.prdctnDisplayData[source],
				"prdctn" : Number(ecsLib.dsplZeroFrmt(prdctnData, 0).replaceAll(",", "")),
				"prdctnExcclc" : Number(ecsLib.dsplZeroFrmt(prdctnExcclcData, 0).replaceAll(",", ""))
			});
		});

		var maxPData = ecsLib.chartDataTotalAmt(chartList, "prdctn");
		var maxCpData = ecsLib.chartDataTotalAmt(chartList, "prdctnExcclc");
		var pInterval = Math.ceil((maxPData / scwin.initData.chart.prdctnIntervalCount) / scwin.initData.chart.prdctnUnit) * scwin.initData.chart.prdctnUnit;
		var cpInterval = Math.ceil((maxCpData / scwin.initData.chart.prdctnIntervalCount) / scwin.initData.chart.prdctnUnit) * scwin.initData.chart.prdctnUnit;

		var sumPData = new Intl.NumberFormat("ko-KR").format(prdctnChartData.reduce((sum, obj) => {
			if (obj.inqireDe == year) {
				return sum + Number(obj.inqireIemVu);
			} else {
				return sum;
			}
		}, 0) || 0);
		var sumCpData = new Intl.NumberFormat("ko-KR").format(prdctnExcclcChartData.reduce((sum, obj) => {
			if (obj.inqireDe == year && obj.iemDivId.endsWith("Inqire")) {
				return sum + Number(obj.inqireIemVu);
			} else {
				return sum;
