	/**
	 * 전력에너지 전주기 현황 생산/소비 데이터를 조회한다.
	 */
	scwin.searchCyclePC = function() {
		var endDt = utilLib.getCurrentDate("yyyy");
		var strtDt = String(Number(endDt) - 4);
		var nowInqireDe = utilLib.calcToday(0, 0, -1);

		var queryString = `?strtDt=${strtDt}`;
		queryString += `&endDt=${endDt}`;
		queryString += `&inqireDe=${nowInqireDe}`;

		var option = {
			action : "ec/main/retrieve-cycle-pc.do" +
				queryString,
			method : "get",
			resData : dltPCData,
			success : "scwin.searchCyclePCCallBack",
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);
	};

	/**
	 * 생산/소비 데이터 조회 콜백
	 */
	scwin.searchCyclePCCallBack = function(res) {
		// 전주기 현황 생산 데이터 설정
		scwin.setRecyclePrdctnData();
		// 전주기 현황 소비 데이터 설정
		scwin.setRecycleCnstnData();
	};

	/**
	* 소비, 소비정산 차트 설정
	 * @param id : 차트 그룹 ID
	 */
	scwin.chartReadyHandlerCnstn = function(id) {
		var cnstnChartData = dltCnstnData.getAllJSON();
		var cnstnExcclcChartData = dltCnstnExcclcData.getAllJSON();
		var year = utilLib.addMonth(utilLib.getCurrentDate("yyyyMM"), -2).substr(0, 4);
		var chartList = [];
		var elcpwstnClsNm = {
			"Itkpl" : "취수장",
			"Prnplc" : "가압장",
			"Fltplt" : "정수장",
			"Etc" : "기타"
		}

		Object.keys(scwin.initData.cnstnDisplayData).forEach(source => {
			var cnstnData = cnstnChartData.filter(obj => obj.inqireDe == year && obj.elcpwstnClsNm.endsWith(elcpwstnClsNm[source])).reduce((sum, obj) => sum + Number(obj.inqireIemVu), 0);
			var cnstnExcclcData = (cnstnExcclcChartData.find(obj => obj.inqireDe == year && obj.iemDivId.endsWith(source.toLowerCase() + "Inqire")) || 0).inqireIemVu;
			cnstnExcclcData = cnstnExcclcData ? cnstnExcclcData : 0;
			chartList.push({
				"name" : scwin.initData.cnstnDisplayData[source],
				"cnstn" : Number(ecsLib.dsplZeroFrmt(cnstnData, 0).replaceAll(",", "")),
				"cnstnExcclc" : Number(ecsLib.dsplZeroFrmt(cnstnExcclcData, 0).replaceAll(",", ""))
			});
		});
		var maxCData = ecsLib.chartDataTotalAmt(chartList, "cnstn");
		var maxCcData = ecsLib.chartDataTotalAmt(chartList, "cnstnExcclc");
		var cInterval = Math.ceil((maxCData / scwin.initData.chart.cnstnIntervalCount) / scwin.initData.chart.cnstnUnit) * scwin.initData.chart.cnstnUnit;
		var ccInterval = Math.ceil((maxCcData / scwin.initData.chart.cnstnIntervalCount) / scwin.initData.chart.cnstnUnit) * scwin.initData.chart.cnstnUnit;

		var sumCData = new Intl.NumberFormat("ko-KR").format(cnstnChartData.reduce((sum, obj) => {
			if (obj.inqireDe == year) {
				return sum + Number(obj.inqireIemVu);
			} else {
				return sum;
			}
		}, 0) || 0);
		var sumCcData = new Intl.NumberFormat("ko-KR").format(cnstnExcclcChartData.reduce((sum, obj) => {
			if (obj.inqireDe == year && obj.iemDivId.endsWith("Inqire")) {
				return sum + Number(obj.inqireIemVu);
			} else {
				return sum;
			}
		}, 0) || 0);
		var titleText = ecsLib.dsplFrmt(sumCData, 0)
			+ ' &lt;span style=&quot;font-size:0.5em;&quot;&gt;MWh&lt;/span&gt;'
			+ '&amp;ensp;&lt;span style=&quot;color:#AFAFAF;font-weight:normal;&quot;&gt;|&lt;/span&gt;&amp;ensp;'
			+ '&lt;span style=&quot;color:#C5385A;&quot;&gt;'
			+ ecsLib.dsplFrmt(sumCcData, 0)
			+ ' &lt;span style=&quot;font-size:0.5em;&quot;&gt;억원&lt;/span&gt;'
			+ '&lt;/span&gt;';

		/*
		var day = utilLib.addDay(utilLib.getCurrentDate("yyyyMMdd"), -1);
		var preDay = day.substr(6, 2);
		var mon = day.substr(4, 2);
		var year = day.substr(0, 4);

		var subTitleText = ' &lt;span style=&quot;font-size:0.5em;&quot;&gt;*&lt;/span&gt;'
			+ year
			+ ' &lt;span style=&quot;font-size:0.5em;&quot;&gt;년 1월 1일부터 &lt;/span&gt;'
			+ year
			+ ' &lt;span style=&quot;font-size:0.5em;&quot;&gt;년 &lt;/span&gt;'
			+ mon
			+ ' &lt;span style=&quot;font-size:0.5em;&quot;&gt;월 &lt;/span&gt;'
			+ preDay
			+ ' &lt;span style=&quot;font-size:0.5em;&quot;&gt;일까지의 전력 소비량과 정산금 데이터입니다.&lt;/span&gt;';
		*/

		/*
		230825 김동현 차장님 요청으로 bold 추가
		*/
		var layoutStr = '<rMateChart backgroundColor="" cornerRadius="12">'
			+ '	<Options>'
			+ '		<Caption text="' + titleText + '" textAlign="right" fontSize="1rem" fontWeight="bold" color="#FD9EA6"'
			+ '			borderStyle="solid" borderColor="#FD9EA6" borderTop="0" borderRight="0" borderBottom="1" borderLeft="0" marginTop="5%" />'
		//	+ '		<SubCaption text="' + subTitleText + '" textAlign="right" marginTop="5%"/>'
			+ '		<Legend position="center" fontSize="0.69rem" vAlign="left" hAlign="top" verticalGap="2" border="0" background="transparent" marginTop="-1%" width="55%" />'
			+ '	</Options>'
			+ '	<Column3DChart showDataTips="true" columnWidthRatio="0.6" type="clustered" dataTipDisplayMode="axis" maxColumnWidth="25" itemClickJsFunction="' + $p.id + 'scwin.chartItemClickHandler">'
			+ '		<horizontalAxis>'
			+ '			<CategoryAxis id="hAxis" categoryField="name" />'
			+ '		</horizontalAxis>'
			+ '		<horizontalAxisRenderers>'
			+ '			<Axis3DRenderer axis="{hAxis}" visible="true" textAlign="right" canDropLabels="false" />'
			+ '		</horizontalAxisRenderers>'
			+ '		<verticalAxis>'
			+ '		</verticalAxis>'
			+ '		<verticalAxisRenderers>'
			+ '			<Axis3DRenderer axis="{vAxisL}" visible="true" placement="left" verticalAxisTitleAlignment="top" titleGap="0" canDropLabels="false" showLine="false" />'
			+ '			<Axis3DRenderer axis="{vAxisR}" visible="true" placement="right" verticalAxisTitleAlignment="top" titleGap="0" canDropLabels="false" showLine="false" />'
			+ '		</verticalAxisRenderers>'
			+ '		<series>'
			+ '			<Column3DSeries color="#222222" fontSize="0.69rem" font-weight="bold" yField="cnstn" displayName="전력 소비량" halfWidthOffset="3">'
			+ '				<verticalAxis>'
			+ '					<LinearAxis id="vAxisL" interval="' + cInterval + '" labelJsFunction="' + $p.id + 'scwin.prdctnLinearLabelHandler" title="MWh" />'
			+ '				</verticalAxis>'
			+ '				<fill>'
			+ '					<SolidColor color="#FD9EA6" />'
			+ '				</fill>'
			+ '				<showDataEffect>'
			+ '					<SeriesInterpolate />'
			+ '				</showDataEffect>'
			+ '			</Column3DSeries>'
			+ '			<Column3DSeries color="#222222" fontSize="0.69rem" font-weight="bold" yField="cnstnExcclc" displayName="소비 정산금" halfWidthOffset="3">'
			+ '				<verticalAxis>'
			+ '					<LinearAxis id="vAxisR" interval="' + ccInterval + '" labelJsFunction="' + $p.id + 'scwin.prdctnLinearLabelHandler" title="억원" />'
			+ '				</verticalAxis>'
			+ '				<fill>'
			+ '					<SolidColor color="#C5385A" />'
			+ '				</fill>'
			+ '				<showDataEffect>'
			+ '					<SeriesInterpolate />'
			+ '				</showDataEffect>'
			+ '			</Column3DSeries>'
			+ '		</series>'
		//	+ '		<annotationElements>'
		//	+ '			<CanvasElement>'
		//	+ '				<Label top="-50" left="50" text="test 입니다." fontSize="16" borderColor="#222222" />'
		//	+ '			</CanvasElement>'
		//	+ '		</annotationElements>'
			+ '	</Column3DChart>'
			+ '</rMateChart>';

		document.getElementById(id).setLayout(layoutStr);
		document.getElementById(id).setData(chartList);
	};

	//============================================================================================
	// 전주기 현황
	//============================================================================================
	/**
	 * 전주기 현황 계획/건설/관리/폐기 데이터를 조회한다.
	 */
	scwin.searchRecyclePbmeData = function() {
		var strtDt = Number(utilLib.getCurrentDate("yyyy")) - 4;
		var endDt = utilLib.getCurrentDate("yyyy");

		var queryString = `?strtDt=${strtDt}`;
		queryString += `&endDt=${endDt}`;

		var option = {
			action : "ec/pbme/retrieve-pbme-sttus.do" +
				queryString,
			method : "get",
			resData : dltCyclePbmeData,
			success : "scwin.searchRecyclePbmeDataCallBack",
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);
	};

	/**
	 * 전주기 현황 계획/건설/관리/폐기 데이터 조회 콜백
	 */
	scwin.searchRecyclePbmeDataCallBack = function() {
		var cyclePbmeData = dltCyclePbmeData.getAllJSON();
		var inqireDe = utilLib.getCurrentDate("yyyy");

		var planCnt = (cyclePbmeData.find(obj => obj.inqireDe == inqireDe && obj.iemDivId == "planComptCnt") || 0).inqireIemVu;
		spnCyclePlanCnt.setLabel(ecsLib.dsplFrmt(planCnt));
		var planCpcty = (cyclePbmeData.find(obj => obj.inqireDe == inqireDe && obj.iemDivId == "planComptEqpCpcty") || 0).inqireIemVu;
		spnCyclePlanCpcty.setLabel(ecsLib.dsplFrmt(planCpcty, 0));
		var planAmt = (cyclePbmeData.find(obj => obj.inqireDe == inqireDe && obj.iemDivId == "planComptAmt") || 0).inqireIemVu;
		spnCyclePlanAmt.setLabel(ecsLib.dsplFrmt(planAmt, 0));
		var cnstrcCnt = (cyclePbmeData.find(obj => obj.inqireDe == inqireDe && obj.iemDivId == "cnstrcComptCnt") || 0).inqireIemVu;
		spnCycleCnstrcCnt.setLabel(ecsLib.dsplFrmt(cnstrcCnt));
		var cnstrcCpcty = (cyclePbmeData.find(obj => obj.inqireDe == inqireDe && obj.iemDivId == "cnstrcComptEqpCpcty") || 0).inqireIemVu;
		spnCycleCnstrcCpcty.setLabel(ecsLib.dsplFrmt(cnstrcCpcty, 0));
		var cnstrcAmt = (cyclePbmeData.find(obj => obj.inqireDe == inqireDe && obj.iemDivId == "cnstrcComptAmt") || 0).inqireIemVu;
		spnCycleCnstrcAmt.setLabel(ecsLib.dsplFrmt(cnstrcAmt, 0));
		var mngReprMntnc = (cyclePbmeData.find(obj => obj.inqireDe == inqireDe && obj.iemDivId == "mngReprMntnc") || 0).inqireIemVu;
		spnCycleMngReprMntnc.setLabel(ecsLib.dsplFrmt(mngReprMntnc));
		var mngRemt = (cyclePbmeData.find(obj => obj.inqireDe == inqireDe && obj.iemDivId == "mngRemt") || 0).inqireIemVu;
		spnCycleMngRemt.setLabel(ecsLib.dsplFrmt(mngRemt));
		var mngChckMntnc = (cyclePbmeData.find(obj => obj.inqireDe == inqireDe && obj.iemDivId == "mngChckMntnc") || 0).inqireIemVu;
		spnCycleMngChckMntnc.setLabel(ecsLib.dsplFrmt(mngChckMntnc));
		var dsuseCnt = (cyclePbmeData.find(obj => obj.inqireDe == inqireDe && obj.iemDivId == "dsuseComptCnt") || 0).inqireIemVu;
		spnCycleDsuseCnt.setLabel(ecsLib.dsplFrmt(dsuseCnt));
		var dsuseCpcty = (cyclePbmeData.find(obj => obj.inqireDe == inqireDe && obj.iemDivId == "dsuseComptEqpCpcty") || 0).inqireIemVu;
		spnCycleDsuseCpcty.setLabel(ecsLib.dsplFrmt(dsuseCpcty, 0));
		var dsuseAmt = (cyclePbmeData.find(obj => obj.inqireDe == inqireDe && obj.iemDivId == "dsuseComptAmt") || 0).inqireIemVu;
		spnCycleDsuseAmt.setLabel(ecsLib.dsplFrmt(dsuseAmt, 0));

		scwin.createCyclePBMECharts();
	};

	/**
	 * 전주기 현황 생산 데이터를 설정한다.
	 */
	scwin.setRecyclePrdctnData = function() {
		var prdctnData = dltPCData.getAllJSON();
		var dData = (prdctnData.find(obj => obj.iemDivId == "dePrdctn") || 0).inqireIemVu;
		var mData = (prdctnData.reduce((sum, obj) => obj.inqireDe.substr(0, 6) == utilLib.addMonth(utilLib.getCurrentDate("yyyyMM"), -1) && obj.iemDivId == "mtPrdctn" && obj.inqireIemVu ? sum + obj.inqireIemVu : sum, 0) || 0);
		var pData = (prdctnData.find(obj => obj.inqireDe.substr(0, 4) == utilLib.getCurrentDate("yyyy") && obj.iemDivId == "yyPrdctn") || 0).inqireIemVu;

		spnCycleDePrdctn.setLabel(ecsLib.dsplZeroFrmt(dData, 0));
		spnCycleMtPrdctn.setLabel(ecsLib.dsplZeroFrmt(mData, 0));
		spnCycleYyPrdctn.setLabel(ecsLib.dsplZeroFrmt(pData, 0));
	};

	/**
	 * 전주기 현황 소비 데이터를 설정한다.
	 */
	scwin.setRecycleCnstnData = function() {
		var cnstnData = dltPCData.getAllJSON();
		var dData = (cnstnData.find(obj => obj.iemDivId == "deCnstn") || 0).inqireIemVu;
		var mData = (cnstnData.reduce((sum, obj) => obj.inqireDe.substr(0, 6) == utilLib.addMonth(utilLib.getCurrentDate("yyyyMM"), -1) && obj.iemDivId == "mtCnstn" && obj.inqireIemVu ? sum + obj.inqireIemVu : sum, 0) || 0);
		var cData = (cnstnData.find(obj => obj.inqireDe.substr(0, 4) == utilLib.getCurrentDate("yyyy") && obj.iemDivId == "yyCnstn") || 0).inqireIemVu;

		spnCycleDeCnstn.setLabel(ecsLib.dsplZeroFrmt(dData, 0));
		spnCycleMtCnstn.setLabel(ecsLib.dsplZeroFrmt(mData, 0));
		spnCycleYyCnstn.setLabel(ecsLib.dsplZeroFrmt(cData, 0));
	};

	// 전주기 현황 정산-발전수익 데이터 조회, 전주기 현황 정산-기타수익 데이터 조회, 전주기 현황 정산-소비정산 데이터 조회, 차트 생산 데이터 조회, 차트 소비 데이터 조회
	scwin.searchPC = async function() {
		var fetchArr = [
			// 전주기 현황 정산-발전수익 데이터를 조회한다.
			scwin.searchElyrsErnData().then(scwin.searchElyrsErnDataCallBack),
			// 전주기 현황 정산-기타수익 데이터 조회
			scwin.searchEtcErnData().then(scwin.searchEtcErnDataCallBack), 
			// 전주기 현황 정산-소비정산 데이터 조회
			scwin.searchCnstnExcclcData().then(scwin.searchCnstnExcclcDataCallBack),
			// 생산 데이터 조회
			scwin.searchChartPrdctn(),
			// 소비 데이터 조회
			scwin.searchChartCnstnData()
		];
		await Promise.all(fetchArr);

		// 하단 PC 차트들 생성
		scwin.createPCCharts();
		// 생산, 소비, 정산 차트 생성
		scwin.createCyclePCCharts();
	};

	/**
	 * 전주기 현황 정산-발전수익 데이터를 조회한다.
	 */
	scwin.searchElyrsErnData = function() {
		return new Promise((resolve, rejext) => {
			var endDt = utilLib.getCurrentDate("yyyy");
			var strtDt = String(Number(endDt) - 4);
			var inqireDe = utilLib.addMonth(utilLib.getCurrentDate("yyyyMM"), -2);

			var queryString = `?strtDt=${strtDt}`;
			queryString += `&endDt=${endDt}`;
			queryString += `&inqireDe=${inqireDe}`;
			queryString += "&ecsBasinDivCd=ALL";

			var option = {
				action : "ec/cl/retrieve-prdctn-excclc.do" +
					queryString,
				method : "get",
				resData : dltElyrsErnData,
				success : function() {
					resolve();
				},
				isShowMeg : false
			};
			ajaxLib.executeAjax($p, option);
		});
	};

