	scwin.setBasinDisplayData = function() {
		dltBasinDisplay.insertJSON(0, scwin.initData.basinDisplayData);
		cbxBasinDisplayData.setNodeSet("data:dltBasinDisplay", "name", "value");
		cbxBasinDisplayData.checkAll();

		// 유역현황도 마우스 오버 이벤트
		scwin.setBasinEvent();
	};

	/**
	 * 체크 박스 선택에 따라 값을 표시한다.
	 */
	scwin.cbxBasinDisplayData_onviewchange = function(info) {
		var index = info.index;
		var checked = info.checked;
		var value = info.value;
		var camelValue = value.charAt(0).toUpperCase() + value.slice(1);
		var prefix = "grp";
		var suffixList = ["DataH", "DataG", "DataN" ,"DataY"];

		if (cbxBasinDisplayData.getSelectedIndex().length < 1) {
			cbxBasinDisplayData.setSelectedIndex(index);
			return;
		}

		for (suffix of suffixList) {
			var emt = $p.getComponentById(prefix + camelValue + suffix);
			emt.setStyle("transform-style", "preserve-3d");
			emt.setStyle("animation", "");
			void document.getElementById(emt.getID()).offsetWidth;
			emt.setStyle("animation", checked ? "main-map-data-anim 300ms ease 0s 1 reverse forwards running" : "main-map-data-anim 300ms ease 0s 1 normal forwards running");
		}
	};

