	/**
	 * 유역 이벤트
	 */
	scwin.setBasinEvent = function() {
		var basins = document.querySelectorAll("#" + $p.getFrameId() + " .main-con-box .map-all-basin g[class*='map-basin-']");
		var labels = document.querySelectorAll("#" + $p.getFrameId() + " .main-con-box div[class*='map-label-box-']");
		var overList = [];
		overList.push(...basins);
		overList.push(...labels);
		var basinCloneMouseoutEvent = function(e) {
			e.target.removeEventListener("mouseout", mouseoutEvent);
			e.target.remove();
		};
		var basinHoverMouseoutEvent = function(e) {
			e.target.removeEventListener("mouseout", mouseoutEvent);
			e.target.classList.remove("basin-hover");
		};
		[...labels].forEach(emt => {
			emt.style.cursor = "pointer";
		});
		overList.forEach(elmt => {
			elmt.addEventListener("mouseover", function(e) {
				if (!this.classList.value.includes("jeju") && !this.classList.value.includes("ulleung")) {
					var mapEmt = e.target;
					if (mapEmt.tagName.toLowerCase() == "g") {
						var jMap = $(mapEmt);
					} else if (mapEmt.tagName.toLowerCase() == "div") {
						var prefix = "map-label-box-";
						var className = [...mapEmt.classList].find(cls => cls.startsWith(prefix));
						if (!className) {
							className = [...mapEmt.parentElement.classList].find(cls => cls.startsWith(prefix));
						}
						var basinName = className.replace(prefix, "");
						var jMap = $(document.querySelector("#" + $p.getFrameId() + " .map-all-basin g.map-basin-" + basinName));
					} else {
						var jMap = $(mapEmt.parentElement);
					}
					var jMapParent = jMap.parent();
					var cloneElmt = jMap.clone();
					cloneElmt[0].id = cloneElmt[0].id + "_";
					cloneElmt[0].classList.add("basin-clone");
					$(".map-all-basin g.basin-clone").remove();
					cloneElmt[0].addEventListener("mouseout", basinCloneMouseoutEvent);
					cloneElmt.appendTo(jMapParent);
					var mapEmt = this;
					if (mapEmt.tagName.toLowerCase() == "g") {
						var jMap = $(mapEmt);
					} else if (mapEmt.tagName.toLowerCase() == "div") {
						var prefix = "map-label-box-";
						var className = [...mapEmt.classList].find(cls => cls.startsWith(prefix));
						if (!className) {
							className = [...mapEmt.parentElement.classList].find(cls => cls.startsWith(prefix));
						}
						var basinName = className.replace(prefix, "");
						var jMap = $(document.querySelector("#" + $p.getFrameId() + " .map-all-basin g.map-basin-" + basinName));
					}
					var jMapParent = jMap.parent();
					jMap[0].classList.add("basin-hover");
					jMap[0].addEventListener("mouseout", basinHoverMouseoutEvent);
					jMap.detach().appendTo(jMapParent);
				}
			});
			elmt.addEventListener("click", function(e) {
				if (!this.classList.value.includes("jeju") && !this.classList.value.includes("ulleung")) {
					var mapEmt = this;
					if (mapEmt.tagName.toLowerCase() == "g") {
						var prefix = "map-basin-";
					} else if (mapEmt.tagName.toLowerCase() == "div") {
						var prefix = "map-label-box-";
					}
					var basinName = [...mapEmt.classList].find(cls => cls.startsWith(prefix)).replace(prefix, "");
					var dataObj = {
						"type" : "json", // 데이터 타입. "json" 권장
						"name" : "param", // 데이터를 가져오기 위한 key 값. popup에서 $p.getParameter("paramJSON")로 깨내올 수 있음.
						"data" : { // 실제 전달할 데이터
							"basin" : basinName.toUpperCase()
						}
					};
					var menuItem = $p.top().wfm_left.getWindow().dltLeftMenuList.getAllJSON().find(obj => obj.menuId.startsWith("ECSEC5") && obj.callParm == basinName.toUpperCase());
					comLib.createWindow(menuItem.menuDc, null, menuItem.scrinUrl, menuItem.menuDc, "main_ecs_detail", "existWindow", null, null, null, null, "wframe", dataObj);
				}
			});
			elmt.addEventListener("mouseout", function(e) {
				var basinHoverEmt = document.querySelectorAll("#" + $p.getFrameId() + " .map-all-basin g.basin-hover");
				[...basinHoverEmt].forEach(emt => {
					emt.removeEventListener("mouseout", basinHoverMouseoutEvent);
					emt.classList.remove("basin-hover")
				});
				var basinClone = document.querySelectorAll("#" + $p.getFrameId() + " .map-all-basin g.basin-clone");
				[...basinClone].forEach(emt => {
					emt.removeEventListener("mouseout", basinCloneMouseoutEvent);
					emt.remove()
				});
			});
		});
	};

	//============================================================================================
	// 차트 슬라이드 기능
	//============================================================================================
	/**
	 * 차트 슬라이드
	 */
	scwin.chartSlide = function(comp, mapping) {
		var mappingKeys = Object.keys(mapping);
		scwin.initData[comp.getOriginalID()] = {};
		scwin.initData[comp.getOriginalID()].chartWrap = document.querySelector(`#${comp.getID()}`);
		var sliderEmt = scwin.initData[comp.getOriginalID()].chartWrap.querySelector("#" + $p.getFrameId() + " .slider");

		for (var i = 0; i < Object.keys(mapping).length; i++) {
			var compId = comp.getOriginalID() + mappingKeys[i];
			$p.dynamicCreate(compId, "group", {}, $p.getComponentById(sliderEmt.id));
			var chartComp = $p.getComponentById(compId);
			chartComp.addClass("slider-item");

			// title 생성 
			$p.dynamicCreate(compId + "Title", "span", {
			}, $p.getComponentById(compId));
			$p.getComponentById(compId + "Title").addClass("main-box-chart-pc-title");
			$p.getComponentById(compId + "Title").setLabel(Object.keys(scwin.initData.chart.displayData[mappingKeys[i]]));

			if (mappingKeys[i] == "PC") {
				$p.dynamicCreate(compId + "TitleInfo", "span", {
				}, $p.getComponentById(compId + "Title"));
				var ym = utilLib.addMonth(utilLib.getCurrentDate("yyyyMM"), -2);
				var info = `&emsp;*${ym.substr(0, 4)}년 ${ym.substr(4, 2)}월까지의 연누계 데이터입니다.`
				$p.getComponentById(compId + "TitleInfo").addClass("main-box-title-info");
				$p.getComponentById(compId + "TitleInfo").setLabel(info);
			}

			// 차트 2개로 분리
			if (mappingKeys[i] == "PC" || mappingKeys[i] == "Prdctn" || mappingKeys[i] == "Cnstn") {
				for (var idx = 1; idx <= 2; idx++) {
					$p.dynamicCreate(compId + "_" + idx, "group", {
					}, $p.getComponentById(compId));
					var chartComp = $p.getComponentById(compId + "_" + idx);
					if (mappingKeys[i] == "PC") {
						chartComp.addClass("main-chart-cpc");
					} else if (mappingKeys[i] == "Prdctn" || mappingKeys[i] == "Cnstn") {
						if (idx == 1) {
							chartComp.addClass("main-chart-pc-left");
						}
						if (idx == 2) {
							chartComp.addClass("main-chart-pc-right");
						}
					}
				}
			}
		};
		scwin.initData[comp.getOriginalID()].sliderWidth = sliderEmt.clientWidth;
		var sliderItems = sliderEmt.querySelectorAll("#" + $p.getFrameId() + " .slider-item");
		var slideCount = sliderItems.length;

		// 버튼 클릭할 때 마다 현재 슬라이드가 어디인지 알려주기 위한 변수
		scwin.initData[comp.getOriginalID()].currSlide = 0;
		// 페이지네이션 생성
		var pagination = scwin.initData[comp.getOriginalID()].chartWrap.querySelector("#" + $p.getFrameId() + " .slider-pagination");

		// 이전 차트 버튼 li
		var compId = comp.getOriginalID() + "PreBtn";
		$p.dynamicCreate(compId, "group", {
			tagname : "li"
		}, $p.getComponentById(pagination.id));

		var liComp = $p.getComponentById(compId);
		liComp.addClass("pagination-btn-item");
		liComp.setTitle("이전");
		document.getElementById(liComp.getID()).innerHTML = "<<";

		// 차트 li
		for (var i = 0; i < mappingKeys.length; i++) {
			compId = comp.getOriginalID() + mappingKeys[i] + "Li";
			$p.dynamicCreate(compId, "group", {
				tagname : "li"
			}, $p.getComponentById(pagination.id));

			liComp = $p.getComponentById(compId);
			liComp.addClass("pagination-item");
			liComp.setTitle(Object.keys(mapping[mappingKeys[i]])[0]);
			document.getElementById(liComp.getID()).innerHTML = "&#9679;";
		};

		// 다음 차트 버튼 li
		compId = comp.getOriginalID() + "NextBtn";
		$p.dynamicCreate(compId, "group", {
			tagname : "li"
		}, $p.getComponentById(pagination.id));

		liComp = $p.getComponentById(compId);
		liComp.addClass("pagination-btn-item");
		liComp.setTitle("다음");
		document.getElementById(liComp.getID()).innerHTML = ">>";

		var paginationItems = scwin.initData[comp.getOriginalID()].chartWrap.querySelectorAll("#" + $p.getFrameId() + " .slider-pagination > .pagination-item");
		var paginationBtnItems = scwin.initData[comp.getOriginalID()].chartWrap.querySelectorAll("#" + $p.getFrameId() + " .slider-pagination > .pagination-btn-item");

		// 페이지네이션 초기 설정_0921
		paginationItems[0].classList.add("active");

		// 슬라이드 넘기기 설정
		var offset = scwin.initData[comp.getOriginalID()].sliderWidth + scwin.initData[comp.getOriginalID()].currSlide;
		offset = 0;
		sliderItems.forEach(emt => {
			emt.setAttribute("style", `left: ${-offset}px`);
		});

		// 각 페이지네이션 클릭 시 해당 슬라이드로 이동하기
		for (var i = 0; i < slideCount; i++) {
			// 각 페이지네이션마다 클릭 이벤트 추가하기
			paginationItems[i].addEventListener("click", e => {
				// 클릭한 페이지네이션에 따라 현재 슬라이드 변경해주기(currSlide는 시작 위치가 1이기 때문에 + 1)
				var i = [...paginationItems].findIndex(emt => emt == e.target);
				scwin.initData[comp.getOriginalID()].currSlide = i;
				// 슬라이드를 이동시키기 위한 offset 계산
				var offset = scwin.initData[comp.getOriginalID()].sliderWidth * scwin.initData[comp.getOriginalID()].currSlide;
				offset = 100 * scwin.initData[comp.getOriginalID()].currSlide;
				sliderItems.forEach(emt => {
					emt.setAttribute("style", `transition: 0.2s; left: ${-offset}%`);
				});
				// 슬라이드 이동 시 현재 활성화된 pagination 변경
				paginationItems.forEach(emt => emt.classList.remove("active"));
				paginationItems[scwin.initData[comp.getOriginalID()].currSlide].classList.add("active");
			});
		}
		// 이전 버튼 클릭 시 해당 슬라이드로 이동하기
		paginationBtnItems[0].addEventListener("click", e => {
			var targetEmt = e.target;
			while(!targetEmt.classList.contains("chart-wrap")) {
				targetEmt = targetEmt.parentElement;
				if (targetEmt.classList.contains("main-chart-pcc") || targetEmt.tagName.toLowerCase() == "body") {
					break;
				}
			}
			var targetEmtOriginalID = targetEmt.id.substr(targetEmt.id.lastIndexOf("_") + "_".length);
			scwin.prevMove(targetEmtOriginalID);
		});
		// 다음 버튼 클릭 시 해당 슬라이드로 이동하기
		paginationBtnItems[1].addEventListener("click", e => {
			var targetEmt = e.target;
			while(!targetEmt.classList.contains("chart-wrap")) {
				targetEmt = targetEmt.parentElement;
				if (targetEmt.classList.contains("main-chart-pcc") || targetEmt.tagName.toLowerCase() == "body") {
					break;
				}
			}
			var targetEmtOriginalID = targetEmt.id.substr(targetEmt.id.lastIndexOf("_") + "_".length);
			scwin.nextMove(targetEmtOriginalID);
		});

		// 브라우저 화면이 조정될 때 마다 slideWidth를 변경하기 위해
		window.addEventListener("resize", e => {
			scwin.initData.grpChartElyrsErn.sliderWidth = scwin.initData.grpChartElyrsErn.chartWrap.querySelector("#" + $p.getFrameId() + " .slider").clientWidth;
		});

		/* 자동 슬라이드 기능 없애달래서 주석처리함_0918
		// 기본적으로 슬라이드 루프 시작하기
		scwin.initData[comp.getOriginalID()].loopInterval = setInterval(() => {
			scwin.nextMove(comp.getOriginalID());
		}, scwin.initData.chart.sliderIntervalTime);
		*/

		// 슬라이드에 마우스가 올라간 경우 루프 멈추기
		scwin.initData[comp.getOriginalID()].chartWrap.addEventListener("mouseover", e => {
			/*
			if (!scwin.initData.chart.dashChartEvent) {
				scwin.initData.chart.dashChartEvent = true;
				setTimeout(() => {
					scwin.initData.chart.dashChartEvent = false;
				}, 200);
			}
			*/
			var targetEmt = e.target;
			while(!targetEmt.classList.contains("chart-wrap")) {
				targetEmt = targetEmt.parentElement;
				if (targetEmt.classList.contains("main-chart-pcc") || targetEmt.tagName.toLowerCase() == "body") {
					break;
				}
			}
			var targetEmtOriginalID = targetEmt.id.substr(targetEmt.id.lastIndexOf("_") + "_".length);
			clearInterval(scwin.initData[targetEmtOriginalID].loopInterval);
		});

		/* 자동 슬라이드 기능 없애달래서 주석처리함_0918
		// 슬라이드에서 마우스가 나온 경우 루프 재시작하기
		scwin.initData[comp.getOriginalID()].chartWrap.addEventListener("mouseout", e => {
			<!--
			var targetEmt = e.target;
			while(!targetEmt.classList.contains("chart-wrap")) {
				targetEmt = targetEmt.parentElement;
				if (targetEmt.classList.contains("main-chart-pcc") || targetEmt.tagName.toLowerCase() == "body") {
					break;
				}
			}
			var targetEmtOriginalID = targetEmt.id.substr(targetEmt.id.lastIndexOf("_") + "_".length);
			clearInterval(scwin.initData[targetEmtOriginalID].loopInterval);
			scwin.initData[targetEmtOriginalID].loopInterval = setInterval(() => {
				scwin.nextMove(targetEmtOriginalID);
			}, scwin.initData.chart.sliderIntervalTime);
			--!>
			// 2023.06.15 마우스 올라가면 전체 멈춤으로 변경
			clearInterval(scwin.initData.grpMainChartList.loopInterval);
			scwin.initData.grpMainChartList.loopInterval = setInterval(() => {
				scwin.nextMove("grpMainChartList");
			}, scwin.initData.chart.sliderIntervalTime);
		});
		*/

		// 드래그(스와이프) 이벤트를 위한 변수 초기화
		scwin.initData.startPoint = 0;
		scwin.initData.endPoint = 0;

		// PC 클릭 이벤트 (드래그)
		scwin.initData[comp.getOriginalID()].chartWrap.addEventListener("mousedown", e => {
			var targetEmt = e.target;
			while(!targetEmt.classList.contains("chart-wrap")) {
				targetEmt = targetEmt.parentElement;
				if (targetEmt.classList.contains("main-chart-pcc") || targetEmt.tagName.toLowerCase() == "body") {
					break;
				}
				targetEmt.style.cursor = "all-scroll";
			}
			// 마우스 드래그 시작 위치 저장
			scwin.initData.startPoint = e.pageX;
		});

		scwin.initData[comp.getOriginalID()].chartWrap.addEventListener("mouseup", e => {
			var targetEmt = e.target;
			while(!targetEmt.classList.contains("chart-wrap")) {
				targetEmt = targetEmt.parentElement;
				if (targetEmt.classList.contains("main-chart-pcc") || targetEmt.tagName.toLowerCase() == "body") {
					break;
				}
				targetEmt.style.cursor = "";
			}
			var targetEmtOriginalID = targetEmt.id.substr(targetEmt.id.lastIndexOf("_") + "_".length);
			// 마우스 드래그 끝 위치 저장
			scwin.initData.endPoint = e.pageX;
			if (scwin.initData.startPoint < scwin.initData.endPoint) {
				// 마우스가 오른쪽으로 드래그 된 경우
				scwin.prevMove(targetEmtOriginalID);
			} else if (scwin.initData.startPoint > scwin.initData.endPoint) {
				// 마우스가 왼쪽으로 드래그 된 경우
				scwin.nextMove(targetEmtOriginalID);
			}
		});
	};

	scwin.nextMove = function(compOriginalID) {
		var sliderEmt = scwin.initData[compOriginalID].chartWrap.querySelector("#" + $p.getFrameId() + " .slider");
		if (!scwin.initData[compOriginalID].sliderWidth) {
			scwin.initData[compOriginalID].sliderWidth = sliderEmt.clientWidth;
		}
		var sliderItems = sliderEmt.querySelectorAll("#" + $p.getFrameId() + " .slider-item");
		var slideCount = sliderItems.length;
		var paginationItems = scwin.initData[compOriginalID].chartWrap.querySelectorAll("#" + $p.getFrameId() + " .slider-pagination > .pagination-item");

		scwin.initData[compOriginalID].currSlide++;
		// 마지막 슬라이드 이상으로 넘어가지 않게 하기 위해서
		if (scwin.initData[compOriginalID].currSlide < slideCount) {
			var offset = 100 * scwin.initData[compOriginalID].currSlide;
			sliderItems.forEach(emt => {
				emt.setAttribute("style", `left: ${-offset}%`);
			});
			// 슬라이드 이동 시 현재 활성화된 pagination 변경
			paginationItems.forEach(emt => emt.classList.remove("active"));
			paginationItems[scwin.initData[compOriginalID].currSlide].classList.add("active");
		} else {
			// 무한 슬라이드 기능 - currSlide 값만 변경해줘도 되지만 시각적으로 자연스럽게 하기 위해 아래 코드 작성
			scwin.initData[compOriginalID].currSlide = 0;
			var offset = 100 * scwin.initData[compOriginalID].currSlide;
			setTimeout(() => {
				// 각 슬라이드 아이템의 left에 offset 적용
				sliderItems.forEach(emt => {
					emt.setAttribute("style", `transition: 0.4s; left: ${-offset}%`);
				});
			}, 0);
			// 슬라이드 이동 시 현재 활성화된 pagination 변경
			paginationItems.forEach(emt => emt.classList.remove("active"));
			paginationItems[scwin.initData[compOriginalID].currSlide].classList.add("active");
		}
	};

	scwin.prevMove = function(compOriginalID) {
		var sliderEmt = scwin.initData[compOriginalID].chartWrap.querySelector("#" + $p.getFrameId() + " .slider");
		if (!scwin.initData[compOriginalID].sliderWidth) {
			scwin.initData[compOriginalID].sliderWidth = sliderEmt.clientWidth;
		}
		var sliderItems = sliderEmt.querySelectorAll("#" + $p.getFrameId() + " .slider-item");
		var slideCount = sliderItems.length;
		var paginationItems = scwin.initData[compOriginalID].chartWrap.querySelectorAll("#" + $p.getFrameId() + " .slider-pagination > .pagination-item");

		scwin.initData[compOriginalID].currSlide--;
		// 1번째 슬라이드 이하로 넘어가지 않게 하기 위해서
		if (scwin.initData[compOriginalID].currSlide >= 0) {
			var offset = 100 * scwin.initData[compOriginalID].currSlide;
			sliderItems.forEach(emt => {
				emt.setAttribute("style", `left: ${-offset}%`);
			});
			// 슬라이드 이동 시 현재 활성화된 pagination 변경
			paginationItems.forEach(emt => emt.classList.remove("active"));
			paginationItems[scwin.initData[compOriginalID].currSlide].classList.add("active");
		} else {
			// 무한 슬라이드 기능 - currSlide 값만 변경해줘도 되지만 시각적으로 자연스럽게 하기 위해 아래 코드 작성
			scwin.initData[compOriginalID].currSlide = slideCount - 1;
			var offset = 100 * scwin.initData[compOriginalID].currSlide;
			setTimeout(() => {
				// 각 슬라이드 아이템의 left에 offset 적용
				sliderItems.forEach(emt => {
					emt.setAttribute("style", `transition: 0.4s; left: ${-offset}%`);
				});
			}, 0);
			// 슬라이드 이동 시 현재 활성화된 pagination 변경
			paginationItems.forEach(emt => emt.classList.remove("active"));
			paginationItems[scwin.initData[compOriginalID].currSlide].classList.add("active");
		}
	};
